import { cloneElement } from 'react'

// Warm tier — FamiliLook family register.
// Softer, rounded defaults for parent/grandparent-facing surfaces.
// Usage: <WarmIcon><EyesIcon /></WarmIcon>
export function WarmIcon({ children, strokeWidth = 2.25, className, style }) {
  if (!children) return null
  return cloneElement(children, {
    strokeWidth,
    strokeLinecap: 'round',
    strokeLinejoin: 'round',
    className,
    style,
  })
}

// Sharp tier — FamiliMatch / FamiliPoker adult register.
// Crisper defaults for Gen Z / competitive adult surfaces.
// Usage: <SharpIcon><CrownIcon /></SharpIcon>
export function SharpIcon({ children, strokeWidth = 1.5, className, style }) {
  if (!children) return null
  return cloneElement(children, {
    strokeWidth,
    strokeLinecap: 'butt',
    strokeLinejoin: 'miter',
    className,
    style,
  })
}
